<div class="d-flex justify-content-between align-items-center mb-4"><div><h2 class="h3 fw-bold mb-1">Materias</h2><p class="text-muted mb-0">Administra materias, submaterias y materias extra.</p></div><a href="<?= e(url('/materias/crear')) ?>" class="btn btn-primary">Nueva materia</a></div>
